45	
46	library	IEEE;
47	use			IEEE.std_logic_1164.all;
48	
49	library	PoC;
50	use			PoC.utils.all;
51	use			PoC.arith.all;
52	
53	
54	entity arith_addw is
55	  generic (
56	    N : positive;                    -- Operand Width
57	    K : positive;                    -- Block Count
58	
59	    ARCH        : tArch     := AAM;        -- Architecture
60	    BLOCKING    : tBlocking := DFLT;       -- Blocking Scheme
61	    SKIPPING    : tSkipping := CCC;        -- Carry Skip Scheme
62			P_INCLUSIVE : boolean   := false       -- Use Inclusive Propagate, i.e. c^1
63	  );
64	  port (
65	    a, b : in std_logic_vector(N-1 downto 0);
66	    cin  : in std_logic;
67	
68	    s    : out std_logic_vector(N-1 downto 0);
69	    cout : out std_logic
70	  );
71	end entity;
72	
73	use std.textio.all;
74	
75	library	IEEE;
76	use			IEEE.numeric_std.all;
77	
78	
79	architecture rtl of arith_addw is
80	
81	  -- Determine Block Boundaries
82	  type tBlocking_vector is array(tArch) of tBlocking;
83	  constant DEFAULT_BLOCKING : tBlocking_vector := (AAM => ASC, CAI => DESC, PAI => DESC, CCA => DESC);
84	
85	  type integer_vector is array(natural range<>) of integer;
86	  impure function compute_blocks return integer_vector is
87	    variable  bs  : tBlocking := BLOCKING;
88	    variable  res : integer_vector(K-1 downto 0);
89	
90	    variable l : line;
91	  begin
92	    if bs = DFLT then
93	      bs := DEFAULT_BLOCKING(ARCH);
94	    end if;
95	    case bs is
96	      when FIX =>
97	        assert N >= K
98	          report "Cannot have more blocks than input bits."
99	          severity failure;
100	        for i in res'range loop
101	          res(i) := ((i+1)*N+K/2)/K;
102	        end loop;
103	
104	      when ASC =>
105	        assert N-K*(K-1)/2 >= K
106	          report "Too few input bits to implement growing block sizes."
107	          severity failure;
108	        for i in res'range loop
109	          res(i) := ((i+1)*(N-K*(K-1)/2)+K/2)/K + (i+1)*i/2;
110	        end loop;
111	
112	      when DESC =>
113	        assert N-K*(K-1)/2 >= K
114	          report "Too few input bits to implement growing block sizes."
115	          severity failure;
116	        for i in res'range loop
117	          res(i) := ((i+1)*(N+K*(K-1)/2)+K/2)/K - (i+1)*i/2;
118	        end loop;
119	
120	      when others =>
121	        report "Unknown blocking scheme: "&tBlocking'image(bs) severity failure;
122	
123	    end case;
124	    --synthesis translate_off
125	    write(l, "Implementing "&integer'image(N)&"-bit wide adder: ARCH="&tArch'image(ARCH)&
126	             ", BLOCKING="&tBlocking'image(bs)&'[');
127	    for i in K-1 downto 1 loop
128	      write(l, res(i)-res(i-1));
129	      write(l, ',');
130	    end loop;
131	    write(l, res(0));
132	    write(l, "], SKIPPING="&tSkipping'image(SKIPPING));
133	    writeline(output, l);
134	    --synthesis translate_on
135	    return  res;
136	  end compute_blocks;
137	  constant BLOCKS : integer_vector(K-1 downto 0) := compute_blocks;
138	
139	  signal g : std_logic_vector(K-1 downto 1);  -- Block Generate
140	  signal p : std_logic_vector(K-1 downto 1);  -- Block Propagate
141	  signal c : std_logic_vector(K-1 downto 1);  -- Block Carry-in
142	begin
143	
144	  -----------------------------------------------------------------------------
145	  -- Rightmost Block + Carry Computation Core
146	  blkCore: block
147	    constant M : positive := BLOCKS(0);  -- Rightmost Block Width
148	  begin
149	
150	    -- Carry Computation with Carry Chain
151	    genCCC: if SKIPPING = CCC generate
152	      signal x, y : unsigned(K+M-2 downto 0);
153	      signal z    : unsigned(K+M-1 downto 0);
154	    begin
155	      x <= unsigned(g & a(M-1 downto 0));
156				genExcl: if not P_INCLUSIVE generate
157					y <= unsigned((g or p) & b(M-1 downto 0));
158					-- carry recovery for other blocks
159					c <= std_logic_vector(z(K+M-2 downto M)) xor p;
160				end generate genExcl;
161				genIncl: if P_INCLUSIVE generate
162					y <= unsigned(p & b(M-1 downto 0));
163					-- carry recovery for other blocks
164					c <= std_logic_vector(z(K+M-2 downto M)) xor (p xor g);
165				end generate genIncl;
166	      z <= ('0' & x) + y + (0 to 0 => cin);
167	
168	      -- output of rightmost block
169	      s(M-1 downto 0) <= std_logic_vector(z(M-1 downto 0));
170	
171	      -- carry output
172	      cout <= z(z'left);
173	    end generate genCCC;
174	
175	    -- LUT-based Carry Computations
176	    genLUT: if SKIPPING /= CCC generate
177	      signal z : unsigned(M downto 0);
178	    begin
179	      -- rightmost block
180	      z <= unsigned('0' & a(M-1 downto 0)) + unsigned(b(M-1 downto 0)) + (0 to 0 => cin);
181	      s(M-1 downto 0) <= std_logic_vector(z(M-1 downto 0));
182	
183	      -- Plain linear LUT-based Carry Forwarding
184	      genPlain: if SKIPPING = PLAIN generate
185	        signal t : std_logic_vector(K downto 1);
186	      begin
187	        -- carry forwarding
188	        t(1)            <= z(M);
189	        t(K downto 2)   <= g or (p and c);
190	        c    <= t(K-1 downto 1);
191	        cout <= t(K);
192	      end generate genPlain;
193	
194				-- Kogge-Stone Parallel Prefix Network
195				genPPN_KS: if SKIPPING = PPN_KS generate
196					subtype tLevel is std_logic_vector(K-1 downto 0);
197					type tLevels is array(natural range<>) of tLevel;
198					constant LEVELS : positive := log2ceil(K);
199					signal   pp, gg : tLevels(0 to LEVELS);
200				begin
201					-- carry forwarding
202					pp(0) <= p & 'X';
203					gg(0) <= g & z(M);
204					genLevels: for i in 1 to LEVELS generate
205						constant D : positive := 2**(i-1);
206					begin
207						pp(i) <= (pp(i-1)(K-1 downto D) and pp(i-1)(K-D-1 downto 0)) & pp(i-1)(D-1 downto 0);
208						gg(i) <= (gg(i-1)(K-1 downto D) or (pp(i-1)(K-1 downto D) and gg(i-1)(K-D-1 downto 0))) & gg(i-1)(D-1 downto 0);
209					end generate genLevels;
210	        c    <= gg(LEVELS)(K-2 downto 0);
211	        cout <= gg(LEVELS)(K-1);
212	      end generate genPPN_KS;
213	
214				-- Brent-Kung Parallel Prefix Network
215				genPPN_BK: if SKIPPING = PPN_BK generate
216					subtype tLevel is std_logic_vector(K-1 downto 0);
217					type tLevels is array(natural range<>) of tLevel;
218					constant LEVELS : positive := log2ceil(K);
219					signal   pp, gg : tLevels(0 to 2*LEVELS-1);
220				begin
221					-- carry forwarding
222					pp(0) <= p & 'X';
223					gg(0) <= g & z(M);
224					genMerge: for i in 1 to LEVELS generate
225						constant D : positive := 2**(i-1);
226					begin
227						genBits: for j in 0 to K-1 generate
228							genOp: if j mod (2*D) = 2*D-1 generate
229								gg(i)(j) <= (pp(i-1)(j) and gg(i-1)(j-D)) or gg(i-1)(j);
230								pp(i)(j) <=  pp(i-1)(j) and pp(i-1)(j-D);
231							end generate;
232							genCp: if j mod (2*D) /= 2*D-1 generate
233								gg(i)(j) <= gg(i-1)(j);
234								pp(i)(j) <= pp(i-1)(j);
235							end generate;
236						end generate;
237					end generate genMerge;
238					genSpread: for i in LEVELS+1 to 2*LEVELS-1 generate
239						constant D : positive := 2**(2*LEVELS-i-1);
240					begin
241						genBits: for j in 0 to K-1 generate
242							genOp: if j > D and (j+1) mod (2*D) = D generate
243								gg(i)(j) <= (pp(i-1)(j) and gg(i-1)(j-D)) or gg(i-1)(j);
244								pp(i)(j) <=  pp(i-1)(j) and pp(i-1)(j-D);
245							end generate;
246							genCp: if j <= D or (j+1) mod (2*D) /= D generate
247								gg(i)(j) <= gg(i-1)(j);
248								pp(i)(j) <= pp(i-1)(j);
249							end generate;
250						end generate;
251					end generate genSpread;
252	        c    <= gg(gg'high)(K-2 downto 0);
253	        cout <= gg(gg'high)(K-1);
254	      end generate genPPN_BK;
255	
256	    end generate genLUT;
257	
258	  end block blkCore;
259	
260	  -----------------------------------------------------------------------------
261	  -- Implement Carry-Select Variant
262	  --
263	  -- all but rightmost block, implementation architecture selected by ARCH
264	  genBlocks: for i in 1 to K-1 generate
265	    -- Covered Index Range
266	    constant LO : positive := BLOCKS(i-1);  -- Low  Bit Index
267	    constant HI : positive := BLOCKS(i)-1;  -- High Bit Index
268	
269	    -- Internal Block Interface
270	    signal aa : unsigned(HI downto LO);
271	    signal bb : unsigned(HI downto LO);
272	    signal ss : unsigned(HI downto LO);
273	  begin
274	
275	    -- Connect common block interface
276	    aa <= unsigned(a(HI downto LO));
277	    bb <= unsigned(b(HI downto LO));
278	    s(HI downto LO) <= std_logic_vector(ss);
279	
280	    -- ARCH-specific Implementations
281	
282	    --Add-Add-Multiplex
283	    genAAM: if ARCH = AAM generate
284	      signal s0 : unsigned(HI+1 downto LO);     -- Block Sum (cin=0)
285	      signal s1 : unsigned(HI+1 downto LO);     -- Block Sum (cin=1)
286	    begin
287	      s0 <= ('0' & aa) + bb;
288	      s1 <= ('0' & aa) + bb + 1;
289	      g(i) <= s0(HI+1);
290				genExcl: if not P_INCLUSIVE generate
291					p(i) <= s1(HI+1) xor s0(HI+1);
292				end generate genExcl;
293				genIncl: if P_INCLUSIVE generate
294					p(i) <= s1(HI+1);
295				end generate genIncl;
296	
297	      ss <= s0(HI downto LO) when c(i) = '0' else s1(HI downto LO);
298	    end generate genAAM;
299	
300	    -- Compare-Add-Increment
301	    genCAI: if ARCH = CAI generate
302	      signal s0 : unsigned(HI+1 downto LO);     -- Block Sum (cin=0)
303	    begin
304	      s0 <= ('0' & aa) + bb;
305	      g(i) <= s0(HI+1);
306				genExcl: if not P_INCLUSIVE generate
307					p(i) <= 'X' when Is_X(std_logic_vector(aa&bb)) else
308									'1' when (aa xor bb) = (aa'range => '1') else '0';
309				end generate genExcl;
310				genIncl: if P_INCLUSIVE generate
311					p(i) <= 'X' when Is_X(std_logic_vector(aa&bb)) else
312									'1' when aa >= not bb else '0';
313				end generate genIncl;
314	      ss <= s0(HI downto LO) when c(i) = '0' else s0(HI downto LO)+1;
315	    end generate genCAI;
316	
317	    -- Propagate-Add-Increment
318	    genPAI: if ARCH = PAI generate
319	      signal s0 : unsigned(HI+1 downto LO);     -- Block Sum (cin=0)
320	    begin
321	      s0 <= ('0' & aa) + bb;
322	      g(i) <= s0(HI+1);
323				genExcl: if not P_INCLUSIVE generate
324					p(i) <= 'X' when Is_X(std_logic_vector(s0)) else
325									'1' when s0(HI downto LO) = (HI downto LO => '1') else '0';
326				end generate genExcl;
327				genIncl: if P_INCLUSIVE generate
328					p(i) <= 'X' when Is_X(std_logic_vector(s0)) else
329									'1' when s0(HI downto LO) = (HI downto LO => '1') else g(i);
330				end generate genIncl;
331	      ss <= s0(HI downto LO) when c(i) = '0' else s0(HI downto LO)+1;
332	    end generate genPAI;
333	
334	    -- Compare-Compare-Add
335	    genCCA: if ARCH = CCA generate
336	      g(i) <= 'X' when Is_X(std_logic_vector(aa&bb)) else
337	              '1' when aa >  not bb else '0';
338				genExcl: if not P_INCLUSIVE generate
339					p(i) <= 'X' when Is_X(std_logic_vector(aa&bb)) else
340									'1' when (aa xor bb) = (aa'range => '1') else '0';
341				end generate genExcl;
342				genIncl: if P_INCLUSIVE generate
343					p(i) <= 'X' when Is_X(std_logic_vector(aa&bb)) else
344									'1' when aa >= not bb else '0';
345				end generate genIncl;
346	      ss <= aa + bb + (0 to 0 => c(i));
347	    end generate genCCA;
348	
349	  end generate genBlocks;
350	
351	end architecture;
352

